  ('social-worker-moex-00835', 'social-worker', 'social-worker-moex-111-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '我國「病人自主權利法」，下列敘述何者正確？', '["係範定與安樂死及協助自殺有關的法規，與歐美國家潮流相符", "為亞洲第一部完整地保障病人自主權利的專法，為保障末期病人家屬為核心的醫療決定", "適用對象僅包括末期病人，不包含植物人或重度失智者等", "緩和醫療是指為減輕或免除病人之生理、心理及靈性痛苦，施予緩解性、支持性之醫療照護"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "fcc05a79b803", "answer_pdf_sha1": "e802327f9e16", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00836', 'social-worker', 'social-worker-moex-111-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '對於臺灣推動性別權益之重要事件，下列何者不是民國100年之後的作為？', '["於行政院成立性別平等處", "制定司法院釋字第748號解釋施行法", "大法官宣告刑法第239條通姦罪違憲", "通過婦女政策綱領，作為擬定婦女相關政策之最高指導原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "fcc05a79b803", "answer_pdf_sha1": "e802327f9e16", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00837', 'social-worker', 'social-worker-moex-111-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '單親母親罹患憂鬱症，讀國中的姊姊被要求請假在家照顧年紀小的弟妹與年邁的外婆；寒暑假與 平時假日打工收入是家中重要收入，姊姊成為家中的實際照顧者。學校對姊姊的印象是缺課，學 業成績落後與人際關係不佳。欲改善姊姊剝奪（deprivation）與排除（exclusion）的生活經驗，下 列何做法相對效益不大？', '["提供姊姊課業輔導與才藝班學費", "協助案弟妹申請公托或課後照顧", "引進長期照顧提供外婆身體照顧與陪診", "心理衛生單位協助母親就醫"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "fcc05a79b803", "answer_pdf_sha1": "e802327f9e16", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00838', 'social-worker', 'social-worker-moex-111-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '提供身心障礙者協助時，下列那個選項無法彰顯「身心障礙者權利公約」（CRPD）之精神？', '["課後配置手語翻譯給聽障學生", "導盲犬可進入教室陪視障學生", "肢障學生轉換教室時，提供輪椅推送", "考試空間與時間與修課同學一致，以維持公平"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "fcc05a79b803", "answer_pdf_sha1": "e802327f9e16", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00839', 'social-worker', 'social-worker-moex-111-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關我國與美國學校社會工作發展的共同之處，下列敘述何者正確？', '["早期學校社會工作者均稱為訪問教師", "均明訂學校社會工作者有資格進行早期療育服務", "早期均由民間社會福利機構開始，協助學校社會工作實務", "均受所得稅法修正影響，促使學校社會工作進入駐校型態"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "fcc05a79b803", "answer_pdf_sha1": "e802327f9e16", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00840', 'social-worker', 'social-worker-moex-111-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '醫院的社會工作者與醫療團隊成員的合作模式，若屬於各自進入無特定互動，無正式溝通機制， 屬於下列何種模式？', '["單一專業模式（uni-disciplinarymodel）", "專業間模式（inter-disciplinarymodel）", "多專業模式（multi-disciplinarymodel）", "跨專業模式（trans-disciplinarymodel）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "fcc05a79b803", "answer_pdf_sha1": "e802327f9e16", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
